const cycleDicts: Record<Language, Record<number, string>> = {
  sk: cycleVibrationDescriptions,
  en: enCycleVibrations,
};

export function getCycleVibrationDescription(cycle: number, lang: Language = 'sk'): string {
  return cycleDicts[lang]?.[cycle] ?? cycleDicts.sk[cycle] ?? '';
}

export function getPlanetSignDescription(planetSkKey: string, signSkKey: string, lang: Language = 'sk'): string | undefined {
  if (lang === 'en') {
    return enPlanetSign[planetSkKey]?.[signSkKey] ?? planetInSignDescriptions[planetSkKey]?.[signSkKey];
  }
  return planetInSignDescriptions[planetSkKey]?.[signSkKey];
}
